previous_heater_on = controller->heater_on;
 previous_state = controller->state;

 /* Handle sensor timeout or invalid input - fail safe */
 if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT || input.kind == CONTROLLER_INPUT_INVALID_TEMPERATURE) {
     controller->has_valid_sensor = false;
     controller_set_safe_off(controller);
     output.heater_on = controller->heater_on;
     output.state = controller->state;
     output.state_name = controller_state_name(controller->state);
     output.changed = (previous_heater_on != controller->heater_on) || (previous_state != controller->state);
     output.timed_out = true;
     return output;
 }

 /* Handle stale sensor data (> 1000ms since last valid frame) */
 if (input.kind == CONTROLLER_INPUT_NONE) {
     uint32_t elapsed_ms = 0;
     if (controller->last_valid_sensor_ms > 0U && input.now_ms >= controller->last_valid_sensor_ms) {
         elapsed_ms = input.now_ms - controller->last_valid_sensor_ms;
     } else if (input.now_ms < controller->last_valid_sensor_ms) {
         /* Wraparound handling */
         elapsed_ms = (UINT32_MAX - controller->last_valid_sensor_ms) + input.now_ms;
     }

     if (elapsed_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
         controller->has_valid_sensor = false;
         controller_set_safe_off(controller);
         output.heater_on = controller->heater_on;
         output.state = controller->state;
         output.state_name = controller_state_name(controller->state);
         output.changed = (previous_heater_on != controller->heater_on) || (previous_state != controller->state);
         output.timed_out = true;
         return output;
     }
     /* No new frame but not yet timeout - hold previous state */
     output.heater_on = controller->heater_on;
     output.state = controller->state;
     output.state_name = controller_state_name(controller->state);
     output.changed = false;
     return output;
 }

 /* Handle valid temperature input */
 if (input.kind == CONTROLLER_INPUT_TEMPERATURE) {
     controller->has_valid_sensor = true;
     controller->last_temperature_c = input.temperature_c;
     controller->last_valid_sensor_ms = input.now_ms;

     int temp = input.temperature_c;
     bool rising = false;

     /* Check if temperature is rising compared to previous sample */
     if (controller->has_valid_sensor && controller->last_temperature_c != 0) {
         rising = (temp > controller->last_temperature_c);
     }

     /* Control policy implementation */
     if (temp < CONTROLLER_TEMP_LOW_THRESHOLD) {
         /* TEMP < 47: turn heater on */
         controller->heater_on = true;
         controller->state = CONTROLLER_STATE_HEATING;
     } else if (temp > CONTROLLER_TEMP_HIGH_THRESHOLD) {
         /* TEMP > 52: turn heater off */
         controller_set_safe_off(controller);
     } else if (temp >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD && temp <= CONTROLLER_TEMP_HIGH_THRESHOLD) {
         /* 50 <= TEMP <= 52: check if rising for early off */
         if (rising) {
             /* Rising temperature in upper band - turn heater off early, count as HOLDING */
             controller->heater_on = false;
             controller->state = CONTROLLER_STATE_HOLDING;
         } else {
             /* Not rising - hold previous safe actuator state */
             controller->state = CONTROLLER_STATE_HOLDING;
         }
     } else if (temp >= CONTROLLER_TEMP_LOW_THRESHOLD && temp < CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) {
         /* 47 <= TEMP < 50: hold previous safe actuator state */
         controller->state = CONTROLLER_STATE_HOLDING;
     }

     output.heater_on = controller->heater_on;
     output.state = controller->state;
     output.state_name = controller_state_name(controller->state);
     output.changed = (previous_heater_on != controller->heater_on) || (previous_state != controller->state);
     return output;
 }

 /* Default case - should not reach here */
 controller_set_safe_off(controller);
 output.heater_on = controller->heater_on;
 output.state = controller->state;
 output.state_name = controller_state_name(controller->state);
 output.changed = (previous_heater_on != controller->heater_on) || (previous_state != controller->state);

 return output;

